import CardCarrito from "./componentes/tarjeta-carrito/card-carrito";
import "./carrito.css"


function Carrito() {

    return (
        <div className="cont-carrito">
            
            <h2>PRODUCTOS</h2>
            
            <CardCarrito />

            <div className="btns-contenedor">
                <button type="submit">Vaciar Carrito</button>
                <button type="submit">Pagar</button>

            </div>

        </div>
    )
}

export default Carrito;
